const form=document.getElementById('uploadForm');let fileInput=document.getElementById('fileInput');const uploadArea=document.querySelector('.upload-area');const statusBox=document.getElementById('statusBox');const statusText=document.getElementById('statusText');const statusContainer=document.getElementById('statusContainer');const progressBar=document.getElementById('progressBar');const results=document.getElementById('results');const imagePreview=document.getElementById('imagePreview');const downloadAll=document.getElementById('downloadAll');function updateStatusMessage(message,type='default'){statusText.textContent=message;statusContainer.classList.remove('status-uploading','status-converting','status-complete','status-error');if(type!=='default'){statusContainer.classList.add(`status-${type}`)}const performanceIndicator=document.getElementById('performanceIndicator');if(type==='uploading'||type==='converting'){performanceIndicator.classList.remove('hidden');updateEstimatedTime()}else{performanceIndicator.classList.add('hidden')}const progressBar=document.querySelector('[role="progressbar"]');if(progressBar&&(type==='uploading'||type==='converting')){const percent=extractPercentage(message)||0;progressBar.setAttribute('aria-valuenow',percent)}}function updateEstimatedTime(){const files=fileInput.files;if(!files||files.length===0)return;const totalSize=Array.from(files).reduce((sum,file)=>sum+file.size,0);const fileCount=files.length;let estimatedTime='';if(totalSize<5*1024*1024){estimatedTime='< 30s'}else if(totalSize<20*1024*1024){estimatedTime='30s - 1m'}else if(totalSize<50*1024*1024){estimatedTime='1-2m'}else{estimatedTime='2-5m'}const timeIndicator=document.getElementById('estimatedTime');if(timeIndicator){timeIndicator.textContent=`Estimated: ${estimatedTime}`}}function extractPercentage(message){const match=message.match(/(\d+)%/);return match?parseInt(match[1]):null}function submitForm(event){event.preventDefault();const files=fileInput.files;if(!files||files.length===0){alert('Please select at least one file to convert.');return}const filePreviewContainer=document.getElementById('filePreviewContainer');if(filePreviewContainer){filePreviewContainer.classList.add('hidden')}updateStatusMessage('Uploading your files...','uploading');const formData=new FormData();for(let i=0;i<files.length;i++){formData.append('files',files[i])}formData.append('format','jpg');const xhr=new XMLHttpRequest();xhr.upload.addEventListener('progress',function(e){if(e.lengthComputable){const percentComplete=(e.loaded/e.total)*100;updateStatusMessage(`Uploading... ${Math.round(percentComplete)}%`,'uploading')}});xhr.addEventListener('load',function(){if(xhr.status===200){const data=JSON.parse(xhr.responseText);updateStatusMessage('Conversion complete!','complete');displayConvertedImages(data)}else{updateStatusMessage('Conversion failed. Please try again.','error')}});xhr.addEventListener('error',function(){updateStatusMessage('Network error. Please check your connection.','error')});xhr.open('POST','/api/convert');xhr.send(formData)}function displayConvertedImages(data){results.innerHTML='';if(!data.files||data.files.length===0){results.innerHTML='<p class="text-red-600">No files were converted successfully.</p>';return}data.files.forEach((fileInfo,index)=>{let fileName;if(typeof fileInfo==='string'){fileName=fileInfo}else if(fileInfo&&fileInfo.filename){fileName=fileInfo.filename}else if(fileInfo&&fileInfo.name){fileName=fileInfo.name}else{console.warn('Invalid file info:',fileInfo);return}const resultItem=createResultItem(fileInfo,index,fileName);results.appendChild(resultItem)});results.classList.remove('hidden');downloadAll.classList.remove('hidden')}function createResultItem(file,index,fileName){const item=document.createElement('div');item.className='result-item bg-white rounded-lg shadow-md p-4 mb-4';const name=document.createElement('h3');name.className='text-lg font-semibold text-gray-800 mb-2';name.textContent=fileName;const thumbnail=document.createElement('img');thumbnail.className='w-full h-48 object-cover rounded-lg mb-3';thumbnail.src=`/converted/${file}`;thumbnail.alt=fileName;thumbnail.loading='lazy';const downloadBtn=document.createElement('a');downloadBtn.className='inline-block bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors';downloadBtn.href=`/converted/${file}`;downloadBtn.download=fileName;downloadBtn.textContent='⬇️ Download';item.appendChild(name);item.appendChild(thumbnail);item.appendChild(downloadBtn);return item}form.addEventListener('submit',submitForm);fileInput.addEventListener('change',function(){const files=this.files;if(files&&files.length>0){const fileNames=Array.from(files).map(file=>file.name).join(', ');document.getElementById('fileCount').textContent=`📁 ${files.length} file(s) selected`;document.getElementById('fileNames').textContent=fileNames;uploadArea.classList.add('hidden');document.getElementById('filePreview').classList.remove('hidden')}});uploadArea.addEventListener('click',()=>fileInput.click());uploadArea.addEventListener('dragover',e=>{e.preventDefault();uploadArea.classList.add('drag-over')});uploadArea.addEventListener('dragleave',()=>uploadArea.classList.remove('drag-over'));uploadArea.addEventListener('drop',e=>{e.preventDefault();uploadArea.classList.remove('drag-over');const dt=e.dataTransfer;const files=dt.files;fileInput.files=files;if(files&&files.length>0){const fileNames=Array.from(files).map(file=>file.name).join(', ');document.getElementById('fileCount').textContent=`📁 ${files.length} file(s) selected`;document.getElementById('fileNames').textContent=fileNames;uploadArea.classList.add('hidden');document.getElementById('filePreview').classList.remove('hidden')}});
